before_code:
module counter_32bit(
  input clk,
  input reset_n,
  input enable,
  output reg [31:0] count
);

  always @(posedge clk) begin
    if (!reset_n)
      count <= 32'b0;
    else if (enable)
      count <= count + 1;
  end

endmodule

after_code:
module counter_32bit(
  input clk,
  input reset_n,
  input enable,
  output reg [31:0] count
);

  always @(posedge clk or negedge reset_n) begin
    if (!reset_n)
      count <= 32'b0;
    else if (enable)
      count <= count + 1;
  end

endmodule
